php artisan prisoner:add '{"name":"Casey Goonan","first_name":"Casey","last_name":"Goonan","description":"Casey Goonan is a Palestine-solidarity activist who on July 2, 2024 set fire to a University of California Police Department vehicle parked on the UC Berkeley campus, in protest of UC investments in companies tied to Israel and the role of campus police in suppressing pro-Palestinian protest during the war in Gaza. He claimed the action publicly. He was arrested by federal authorities and pleaded guilty in 2025 to federal arson and use of fire to commit a federal felony. He was sentenced to approximately seven years in federal prison with the federal terrorism enhancement applied — among the longest sentences imposed on a U.S. anti-war activist in the post-October 7 Palestine solidarity wave.","state":"California","gender":"Male","ideologies":["Anti-war","Palestine solidarity","Anti-imperialist"],"in_custody":true,"released":false,"cases":[{"institution_name":"Federal Bureau of Prisons","institution_state":"California","charges":"Federal arson; use of fire to commit a federal felony — July 2, 2024 firebombing of a UC Berkeley police vehicle in protest of UC investments in Israel and U.S. support for the war in Gaza","arrest_date":"2024-07-02","incarceration_date":"2024-07-02","sentence":"~84 months federal prison with terrorism enhancement","convicted":"Yes — guilty plea, 2025"}]}'

php artisan prisoner:add '{"name":"Ruby Montoya","first_name":"Ruby","last_name":"Montoya","description":"Ruby Montoya is an environmental and Indigenous-solidarity activist and the co-defendant of Jessica Reznicek (also in this database) in the federal prosecution of the 2016-2017 Dakota Access Pipeline sabotage campaign in Iowa. The two used oxyacetylene torches to burn through exposed pipeline valves and disable construction equipment at multiple sites, in an attempt to halt completion of the pipeline that crosses Standing Rock Sioux water sources. They publicly claimed the actions in a 2017 press conference at the Iowa Utilities Board. Montoya pleaded guilty in 2021 to conspiracy to damage an energy facility. She was sentenced in August 2022 to 72 months in federal prison with the federal terrorism enhancement applied, plus restitution of approximately three million dollars jointly with Reznicek.","state":"Iowa","gender":"Female","ideologies":["Environmental","Indigenous solidarity","Anti-pipeline"],"affiliation":["Catholic Worker"],"in_custody":true,"released":false,"cases":[{"institution_name":"Federal Bureau of Prisons","institution_state":"Iowa","charges":"Conspiracy to damage an energy facility; arson — 2016-2017 Dakota Access Pipeline sabotage in Iowa","incarceration_date":"2022-08-15","sentence":"72 months federal prison with terrorism enhancement; ~$3M restitution joint with Jessica Reznicek","convicted":"Yes — guilty plea, 2021"}]}'

php artisan prisoner:add '{"name":"Leqaa Kordia","first_name":"Leqaa","last_name":"Kordia","description":"Leqaa Kordia is a Palestinian woman and longtime New Jersey resident who was detained by ICE in March 2025 as part of the Trump administrations campaign of immigration enforcement against participants in pro-Palestinian campus protests. She had attended demonstrations in the Columbia University area. She was arrested in Newark and transferred to the Prairieland Detention Center in Texas, where she was held for months. Federal authorities cited an alleged visa overstay rather than any criminal charge, but the targeting was widely understood as retaliation for her protest activity.","state":"New Jersey","race":"Arab","gender":"Female","ideologies":["Palestine solidarity","Anti-War"],"in_custody":false,"released":true,"cases":[{"institution_name":"Prairieland Detention Center","institution_city":"Alvarado","institution_state":"Texas","charges":"Immigration detention — ICE arrest framed as visa overstay; widely understood as targeting for Columbia-area pro-Palestinian protest activity. No criminal charges.","arrest_date":"2025-03-14","incarceration_date":"2025-03-14","sentence":"Held in immigration detention for several months at Prairieland","convicted":"No — immigration detention, no criminal charges"}]}'

php artisan prisoner:add '{"name":"Alireza Doroudi","first_name":"Alireza","last_name":"Doroudi","description":"Alireza Doroudi is an Iranian PhD student in mechanical engineering at the University of Alabama who was arrested at his home in Tuscaloosa by ICE on March 25, 2025, as part of the Trump administrations wave of visa revocations and detentions targeting international students associated with pro-Palestinian campus activism. The U.S. State Department revoked his student visa. He was held in immigration detention at the LaSalle ICE Processing Center in Jena, Louisiana. Rather than continue fighting the case from detention, he chose to self-deport to Iran in April 2025.","state":"Alabama","race":"Arab","gender":"Male","ideologies":["Palestine solidarity","Anti-War"],"in_custody":false,"released":true,"in_exile":true,"cases":[{"institution_name":"LaSalle ICE Processing Center","institution_city":"Jena","institution_state":"Louisiana","charges":"Immigration detention — student visa revoked by U.S. State Department in March 2025 in connection with the Trump administrations targeting of pro-Palestinian international students. No criminal charges.","arrest_date":"2025-03-25","incarceration_date":"2025-03-25","release_date":"2025-04-15","sentence":"Held approximately three weeks in ICE detention; self-deported to Iran","convicted":"No — immigration detention, no criminal charges"}]}'

