php artisan prisoner:add '{"name":"Dalton Trumbo","first_name":"Dalton","last_name":"Trumbo","description":"James Dalton Trumbo was one of the most prolific and successful screenwriters in Hollywood history (Roman Holiday, Spartacus, Exodus, Johnny Got His Gun) and the most public face of the Hollywood Ten — the ten Hollywood writers, directors, and producers cited for contempt of Congress in November 1947 after refusing on First Amendment grounds to answer the House Un-American Activities Committees demand to know whether they were members of the Communist Party USA. He was a member at the time he was called to testify and made no secret of it after the fact.\n\nAfter exhausting appeals, Trumbo served 11 months at the federal prison camp in Ashland, Kentucky beginning June 1950, alongside fellow Hollywood Ten member John Howard Lawson. While imprisoned he encountered J. Parnell Thomas, the very HUAC chairman who had cited him for contempt, who was serving his own sentence at Danbury for embezzlement.\n\nReleased in 1951, Trumbo was blacklisted from Hollywood for the next decade and continued working under pseudonyms and front writers, winning two Academy Awards under names other than his own (Roman Holiday in 1953, The Brave One in 1956). His public hiring by Otto Preminger in 1960 for Exodus and Kirk Douglas for Spartacus is generally considered the moment that broke the Hollywood blacklist.","state":"California","race":"White","gender":"Male","birthdate":"1905-12-09","death_date":"1976-09-10","ideologies":["Communism","First Amendment"],"affiliation":["Communist Party USA","Hollywood Ten","Screen Writers Guild"],"in_custody":false,"released":true,"cases":[{"institution_name":"Federal Correctional Institution, Ashland","institution_city":"Ashland","institution_state":"Kentucky","charges":"Contempt of Congress — refusing on First Amendment grounds to answer the House Un-American Activities Committees questions about Communist Party membership (Hollywood Ten)","arrest_date":"1947-11-24","incarceration_date":"1950-06-09","release_date":"1951-05-01","sentence":"11 months federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the District of Columbia, 1948; conviction affirmed on appeal in 1949"}]}'

php artisan prisoner:add '{"name":"John Howard Lawson","first_name":"John","middle_name":"Howard","last_name":"Lawson","description":"John Howard Lawson was a screenwriter, the first president of the Screen Writers Guild, and the leading Marxist theorist among Hollywood writers. As the most senior member of the Hollywood Ten, he was the first witness called before the House Un-American Activities Committee in October 1947 and the first to refuse on First Amendment grounds to answer questions about Communist Party membership. He was cited for contempt of Congress on November 24, 1947, exhausted his appeals, and served one year at the federal prison camp in Ashland, Kentucky beginning June 1950 alongside Dalton Trumbo. After his release he was permanently blacklisted from Hollywood and lived the rest of his life as a Marxist theatre critic and historian.","state":"California","race":"White","gender":"Male","birthdate":"1894-09-25","death_date":"1977-08-11","ideologies":["Communism","First Amendment"],"affiliation":["Communist Party USA","Hollywood Ten","Screen Writers Guild"],"in_custody":false,"released":true,"cases":[{"institution_name":"Federal Correctional Institution, Ashland","institution_city":"Ashland","institution_state":"Kentucky","charges":"Contempt of Congress — refusing on First Amendment grounds to answer HUACs questions about Communist Party membership (Hollywood Ten)","arrest_date":"1947-11-24","incarceration_date":"1950-06-09","release_date":"1951-06-09","sentence":"1 year federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the District of Columbia, 1948"}]}'

php artisan prisoner:add '{"name":"Ring Lardner Jr.","first_name":"Ring","middle_name":"Wilmer","last_name":"Lardner Jr.","description":"Ringgold Wilmer Lardner Jr. was an Academy Award-winning screenwriter (Woman of the Year, M*A*S*H) and one of the Hollywood Ten. Asked by the House Un-American Activities Committee in October 1947 whether he was a member of the Communist Party, he gave the most famous of all the Tens responses: I could answer the way you want, Mr. Chairman, but I would hate myself in the morning. He was cited for contempt of Congress on November 24, 1947 and after exhausting appeals served nine months at the federal prison camp in Danbury, Connecticut beginning 1950, alongside fellow Hollywood Ten member Lester Cole. He was blacklisted for the next thirteen years and worked under pseudonyms and fronts during that time.","state":"California","race":"White","gender":"Male","birthdate":"1915-08-19","death_date":"2000-10-31","ideologies":["Communism","First Amendment"],"affiliation":["Communist Party USA","Hollywood Ten","Screen Writers Guild"],"in_custody":false,"released":true,"cases":[{"institution_name":"Federal Correctional Institution, Danbury","institution_city":"Danbury","institution_state":"Connecticut","charges":"Contempt of Congress — refusing on First Amendment grounds to answer HUACs questions about Communist Party membership (Hollywood Ten)","arrest_date":"1947-11-24","incarceration_date":"1950-06-09","release_date":"1951-03-09","sentence":"9 months federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the District of Columbia, 1948"}]}'

php artisan prisoner:add '{"name":"Albert Maltz","first_name":"Albert","last_name":"Maltz","description":"Albert Maltz was a novelist, short-story writer, and screenwriter (This Gun for Hire, Pride of the Marines, Destination Tokyo) and one of the Hollywood Ten. Cited for contempt of Congress on November 24, 1947 for refusing on First Amendment grounds to answer HUACs questions about Communist Party membership, he served nine months at the federal prison camp in Mill Point, West Virginia beginning June 1950 alongside Edward Dmytryk. He was blacklisted for the rest of his Hollywood career and worked under pseudonyms; he later wrote the Frank Sinatra short film The House I Live In, which won an honorary Academy Award in 1946 — before the blacklist — for its plea against anti-Semitism. He lived in Mexico for many years to escape the blacklist.","state":"California","race":"White","gender":"Male","birthdate":"1908-10-28","death_date":"1985-04-26","ideologies":["Communism","First Amendment"],"affiliation":["Communist Party USA","Hollywood Ten"],"in_custody":false,"released":true,"cases":[{"institution_name":"Federal Correctional Institution, Mill Point","institution_city":"Mill Point","institution_state":"West Virginia","charges":"Contempt of Congress — refusing on First Amendment grounds to answer HUACs questions about Communist Party membership (Hollywood Ten)","arrest_date":"1947-11-24","incarceration_date":"1950-06-09","release_date":"1951-03-09","sentence":"9 months federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the District of Columbia, 1948"}]}'

php artisan prisoner:add '{"name":"Alvah Bessie","first_name":"Alvah","last_name":"Bessie","description":"Alvah Cecil Bessie was a novelist, screenwriter (Objective, Burma!), and Spanish Civil War veteran (he had fought in the Abraham Lincoln Brigade against Franco) who became one of the Hollywood Ten. Cited for contempt of Congress on November 24, 1947 for refusing on First Amendment grounds to answer HUACs questions about Communist Party membership, he served ten months at the federal prison camp in Texarkana, Texas beginning June 1950 alongside Hollywood Ten director Herbert Biberman. After his release he was permanently blacklisted from Hollywood and worked the rest of his life in San Francisco as a writer and as a stage manager at the hungry i nightclub. His memoir of the blacklist period, Inquisition in Eden, appeared in 1965.","state":"California","race":"White","gender":"Male","birthdate":"1904-06-04","death_date":"1985-07-21","ideologies":["Communism","Anti-fascist","First Amendment"],"affiliation":["Communist Party USA","Hollywood Ten","Abraham Lincoln Brigade"],"in_custody":false,"released":true,"cases":[{"institution_name":"Federal Correctional Institution, Texarkana","institution_city":"Texarkana","institution_state":"Texas","charges":"Contempt of Congress — refusing on First Amendment grounds to answer HUACs questions about Communist Party membership (Hollywood Ten)","arrest_date":"1947-11-24","incarceration_date":"1950-06-09","release_date":"1951-04-09","sentence":"10 months federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the District of Columbia, 1948"}]}'

php artisan prisoner:add '{"name":"Herbert Biberman","first_name":"Herbert","last_name":"Biberman","description":"Herbert J. Biberman was a film director and one of the Hollywood Ten. Cited for contempt of Congress on November 24, 1947 for refusing on First Amendment grounds to answer HUACs questions about Communist Party membership, he served six months at the federal prison camp in Texarkana, Texas beginning June 1950 alongside Hollywood Ten member Alvah Bessie. After his release and despite the blacklist, he directed the 1954 independent film Salt of the Earth — a sympathetic portrait of a New Mexico zinc miners strike — which was one of the most suppressed films in U.S. history; the projectionists union refused to handle it, theaters refused to screen it, and the lead actress, Rosaura Revueltas, was deported to Mexico mid-shoot. Salt of the Earth is now in the U.S. National Film Registry of the Library of Congress. Biberman was married to Academy Award-winning actress Gale Sondergaard, who was also blacklisted.","state":"California","race":"White","gender":"Male","birthdate":"1900-03-04","death_date":"1971-06-30","ideologies":["Communism","First Amendment"],"affiliation":["Communist Party USA","Hollywood Ten"],"in_custody":false,"released":true,"cases":[{"institution_name":"Federal Correctional Institution, Texarkana","institution_city":"Texarkana","institution_state":"Texas","charges":"Contempt of Congress — refusing on First Amendment grounds to answer HUACs questions about Communist Party membership (Hollywood Ten)","arrest_date":"1947-11-24","incarceration_date":"1950-06-09","release_date":"1950-12-09","sentence":"6 months federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the District of Columbia, 1948"}]}'

php artisan prisoner:add '{"name":"Lester Cole","first_name":"Lester","last_name":"Cole","description":"Lester Cole was a screenwriter (Born Free, the credit pseudonymously written from the blacklist) and one of the original founders of the Screen Writers Guild. Cited for contempt of Congress on November 24, 1947 as one of the Hollywood Ten for refusing on First Amendment grounds to answer HUACs questions about Communist Party membership, he served one year at the federal prison camp in Danbury, Connecticut beginning June 1950 alongside Ring Lardner Jr. He was blacklisted for the rest of his Hollywood career and continued writing under pseudonyms. He spent his last decades teaching screenwriting at the San Francisco Art Institute and at the University of California, Berkeley.","state":"California","race":"White","gender":"Male","birthdate":"1904-06-19","death_date":"1985-08-15","ideologies":["Communism","First Amendment"],"affiliation":["Communist Party USA","Hollywood Ten","Screen Writers Guild"],"in_custody":false,"released":true,"cases":[{"institution_name":"Federal Correctional Institution, Danbury","institution_city":"Danbury","institution_state":"Connecticut","charges":"Contempt of Congress — refusing on First Amendment grounds to answer HUACs questions about Communist Party membership (Hollywood Ten)","arrest_date":"1947-11-24","incarceration_date":"1950-06-09","release_date":"1951-06-09","sentence":"1 year federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the District of Columbia, 1948"}]}'

php artisan prisoner:add '{"name":"Edward Dmytryk","first_name":"Edward","last_name":"Dmytryk","description":"Edward Dmytryk was a film director (Murder, My Sweet; Crossfire; The Caine Mutiny) and one of the Hollywood Ten. Cited for contempt of Congress on November 24, 1947 for refusing on First Amendment grounds to answer HUACs questions about Communist Party membership, he served six months at the federal prison camp in Mill Point, West Virginia beginning June 1950 alongside Albert Maltz. Unlike the other nine, Dmytryk reversed his position after his release: in April 1951 he gave a second appearance before HUAC in which he named twenty-six Communists and former Communists in the film industry. His decision broke the unity of the Hollywood Ten and made him a deeply divisive figure in Hollywood for the rest of his life. He resumed his directorial career and continued working through the 1980s.","state":"California","race":"White","gender":"Male","birthdate":"1908-09-04","death_date":"1999-07-01","ideologies":["Communism (former)","First Amendment"],"affiliation":["Hollywood Ten"],"in_custody":false,"released":true,"cases":[{"institution_name":"Federal Correctional Institution, Mill Point","institution_city":"Mill Point","institution_state":"West Virginia","charges":"Contempt of Congress — refusing on First Amendment grounds to answer HUACs questions about Communist Party membership (Hollywood Ten)","arrest_date":"1947-11-24","incarceration_date":"1950-06-09","release_date":"1950-12-09","sentence":"6 months federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the District of Columbia, 1948"}]}'

php artisan prisoner:add '{"name":"Adrian Scott","first_name":"Adrian","last_name":"Scott","description":"Adrian Scott was a film producer (Murder, My Sweet; Crossfire) and one of the Hollywood Ten. Cited for contempt of Congress on November 24, 1947 for refusing on First Amendment grounds to answer HUACs questions about Communist Party membership, he served one year at the federal prison camp in Ashland, Kentucky beginning June 1950 alongside Dalton Trumbo and John Howard Lawson. He was permanently blacklisted from Hollywood production and spent the rest of his life unable to work openly in his field. Scott was the producing partner of co-Hollywood Ten member Edward Dmytryk; the two had together made the Academy Award-nominated 1947 anti-anti-Semitism drama Crossfire shortly before being subpoenaed.","state":"California","race":"White","gender":"Male","birthdate":"1911-02-06","death_date":"1972-12-25","ideologies":["Communism","First Amendment"],"affiliation":["Communist Party USA","Hollywood Ten"],"in_custody":false,"released":true,"cases":[{"institution_name":"Federal Correctional Institution, Ashland","institution_city":"Ashland","institution_state":"Kentucky","charges":"Contempt of Congress — refusing on First Amendment grounds to answer HUACs questions about Communist Party membership (Hollywood Ten)","arrest_date":"1947-11-24","incarceration_date":"1950-06-09","release_date":"1951-06-09","sentence":"1 year federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the District of Columbia, 1948"}]}'

php artisan prisoner:add '{"name":"Samuel Ornitz","first_name":"Samuel","last_name":"Ornitz","description":"Samuel Badisch Ornitz was a screenwriter (Hell Ship Morgan, Three Faces West) and a founding member of the Screen Writers Guild. He was the oldest of the Hollywood Ten and was already in poor health when he was cited for contempt of Congress on November 24, 1947 for refusing on First Amendment grounds to answer HUACs questions about Communist Party membership. He served his nine-month sentence at the U.S. Medical Center for Federal Prisoners in Springfield, Missouri beginning June 1950, where he was held in the prison hospital throughout. He died of cancer in 1957 at age 66, never having worked in Hollywood again.","state":"California","race":"White","gender":"Male","birthdate":"1890-11-15","death_date":"1957-03-10","ideologies":["Communism","First Amendment"],"affiliation":["Communist Party USA","Hollywood Ten","Screen Writers Guild"],"in_custody":false,"released":true,"cases":[{"institution_name":"U.S. Medical Center for Federal Prisoners","institution_city":"Springfield","institution_state":"Missouri","charges":"Contempt of Congress — refusing on First Amendment grounds to answer HUACs questions about Communist Party membership (Hollywood Ten)","arrest_date":"1947-11-24","incarceration_date":"1950-06-09","release_date":"1951-03-09","sentence":"9 months federal prison; served in the prison hospital due to advanced illness","convicted":"Yes — federal jury verdict, U.S. District Court for the District of Columbia, 1948"}]}'

