php artisan prisoner:add '{"name":"Fleeta Drumgo","first_name":"Fleeta","last_name":"Drumgo","description":"Fleeta Drumgo was a Black prisoner at Soledad Prison in California and one of the three men known as the Soledad Brothers — alongside George Jackson and John Cluchette — who in February 1970 were charged with the murder of Soledad guard John Mills. Mills had been beaten to death and thrown from a tier days after a white guard in the Soledad yard shot and killed three Black prisoners during a fight. There was no physical evidence connecting any of the three men to the killing. The case became an international cause and the focus of the Soledad Brothers Defense Committee, with Angela Davis as one of its central organizers. After George Jackson was killed by guards at San Quentin on August 21, 1971, three days before the trial was set to begin, Drumgo and Cluchette were tried together. On March 27, 1972, the jury acquitted both men of all charges. Drumgo was released and continued political organizing in Oakland. He was killed in an unrelated 1979 shooting at age 33.","state":"California","race":"Black","gender":"Male","birthdate":"1945-12-27","death_date":"1979-06-27","ideologies":["Black Liberation"],"affiliation":["Soledad Brothers"],"in_custody":false,"released":true,"cases":[{"institution_name":"San Quentin State Prison","institution_state":"California","charges":"Murder of Soledad guard John Mills (Soledad Brothers prosecution)","arrest_date":"1970-02-16","incarceration_date":"1970-02-16","release_date":"1972-03-27","sentence":"Acquitted by jury after more than two years held in pretrial custody at San Quentin","convicted":"No — acquitted by California state jury on March 27, 1972"}]}'

php artisan prisoner:add '{"name":"John Cluchette","first_name":"John","last_name":"Cluchette","description":"John Cluchette was a Black prisoner at Soledad Prison in California and one of the three Soledad Brothers — alongside George Jackson and Fleeta Drumgo — charged in February 1970 with the murder of Soledad guard John Mills. The charge was based on no physical evidence; the case was widely understood as retaliation against politically active Black prisoners. The Soledad Brothers Defense Committee, with Angela Davis as one of its central organizers, made the case an international cause. After George Jackson was killed by guards at San Quentin on August 21, 1971, three days before the trial was set to begin, Cluchette and Drumgo were tried together. On March 27, 1972, the jury acquitted both men of all charges. Cluchette completed an unrelated earlier sentence and was released in the late 1970s.","state":"California","race":"Black","gender":"Male","birthdate":"1944-04-26","ideologies":["Black Liberation"],"affiliation":["Soledad Brothers"],"in_custody":false,"released":true,"cases":[{"institution_name":"San Quentin State Prison","institution_state":"California","charges":"Murder of Soledad guard John Mills (Soledad Brothers prosecution)","arrest_date":"1970-02-16","incarceration_date":"1970-02-16","release_date":"1972-03-27","sentence":"Acquitted by jury after more than two years held in pretrial custody at San Quentin","convicted":"No — acquitted by California state jury on March 27, 1972"}]}'

