php artisan prisoner:add '{"name":"Margaret Sanger","first_name":"Margaret","last_name":"Sanger","description":"Margaret Higgins Sanger was an American nurse, sex educator, and birth control activist who founded the first birth control clinic in the United States. On October 16, 1916, she opened the clinic in a storefront at 46 Amboy Street in the Brownsville neighborhood of Brooklyn, New York. Within ten days, undercover police arrested Sanger, her sister Ethel Byrne, and clinic worker Fania Mindell for distributing contraceptives and contraceptive information in violation of New Yorks Comstock-era anti-obscenity statutes. Sanger was tried in early 1917 and sentenced to 30 days in the Queens County Penitentiary, which she served. The arrests catalyzed national press coverage and a sustained legal campaign that gradually weakened state-level Comstock restrictions. Sanger went on to found what became the Planned Parenthood Federation of America. Her broader record included support for eugenics policies common in the Progressive Era — a serious and well-documented part of her history that the modern Planned Parenthood organization has formally repudiated.","state":"New York","race":"White","gender":"Female","birthdate":"1879-09-14","death_date":"1966-09-06","ideologies":["Reproductive rights","Feminism"],"affiliation":["American Birth Control League","Planned Parenthood"],"in_custody":false,"released":true,"cases":[{"institution_name":"Queens County Penitentiary","institution_state":"New York","charges":"Distributing contraceptives and contraceptive information in violation of New York anti-obscenity statutes (Comstock-era law)","arrest_date":"1916-10-26","incarceration_date":"1917-02-05","release_date":"1917-03-06","sentence":"30 days at the Queens County Penitentiary","convicted":"Yes — New York state court, 1917"}]}'

